void main(){
  vec2 uv = gl_FragCoord.xy / u_resolution.xy;
  float sheen = smoothstep(0.35, 0.65, sin((uv.x + uv.y) * 3.1416 + u_time * 0.4) * 0.5 + 0.5);
  vec3 tint = mix(vec3(0.75, 0.82, 0.95), vec3(0.92, 0.95, 1.0), sheen);
  float edge = smoothstep(1.0, 0.4, distance(uv, vec2(0.5)));
  float a = 0.16 + 0.10 * sheen + 0.06 * edge;
  gl_FragColor = vec4(tint, a);
}

void main(){
  vec2 uv = gl_FragCoord.xy / u_resolution.xy;
  float t = u_time * 0.3;
  float w = sin(uv.x * 6.0 + t) * 0.10 + sin(uv.x * 3.0 - t * 1.3) * 0.15;
  float band = smoothstep(0.16, 0.0, abs(uv.y - 0.5 - w));
  vec3 c = mix(vec3(0.10, 0.85, 0.65), vec3(0.35, 0.45, 0.95), uv.x);
  vec3 col = vec3(0.02, 0.03, 0.08) + c * band;
  gl_FragColor = vec4(col, 1.0);
}

float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453); }
void main(){
  vec2 uv = gl_FragCoord.xy / u_resolution.xy;
  float g = hash(floor(gl_FragCoord.xy) + u_time);
  vec3 base = mix(vec3(0.08, 0.09, 0.12), vec3(0.16, 0.17, 0.22), uv.y);
  vec3 col = base + (g - 0.5) * 0.12;
  gl_FragColor = vec4(col, 1.0);
}

